3	/**
4	 * Creates an ID generator.
5	 * The total length of the ID is the sum of the prefix, separator, and random part length.
6	 * Not cryptographically secure.
7	 *
8	 * @param alphabet - The alphabet to use for the ID. Default: '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz'.
9	 * @param prefix - The prefix of the ID to generate. Optional.
10	 * @param separator - The separator between the prefix and the random part of the ID. Default: '-'.
11	 * @param size - The size of the random part of the ID to generate. Default: 16.
12	 */
13	export const createIdGenerator = ({
14	  prefix,
15	  size = 16,
16	  alphabet = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz',
17	  separator = '-',
18	}: {
19	  prefix?: string;
20	  separator?: string;
21	  size?: number;
22	  alphabet?: string;
23	} = {}): IdGenerator => {
24	  const generator = () => {
25	    const alphabetLength = alphabet.length;
26	    const chars = new Array(size);
27	    for (let i = 0; i < size; i++) {
28	      chars[i] = alphabet[(Math.random() * alphabetLength) | 0];
29	    }
30	    return chars.join('');
31	  };
32	
33	  if (prefix == null) {
34	    return generator;
35	  }
36	
37	  // check that the prefix is not part of the alphabet (otherwise prefix checking can fail randomly)
38	  if (alphabet.includes(separator)) {
39	    throw new InvalidArgumentError({
40	      argument: 'separator',
41	      message: `The separator "${separator}" must not be part of the alphabet "${alphabet}".`,
42	    });
43	  }
44	
45	  return () => `${prefix}${separator}${generator()}`;
46	};
47	
48	/**
49	 * A function that generates an ID.
50	 */
51	export type IdGenerator = () => string;
52	
53	/**
54	 * Generates a 16-character random string to use for IDs.
55	 * Not cryptographically secure.
56	 */
57	export const generateId = createIdGenerator();
