        }
        if (
          data.useMultipleImages !== undefined &&
          data.useMultipleImages !== null
        ) {
          result.useMultipleImages = data.useMultipleImages;
        }

        for (const [key, value] of Object.entries(data)) {
          if (
            ![
              // camelCase known keys
              'imageUrl',
              'maskUrl',
              'guidanceScale',
              'numInferenceSteps',
              'enableSafetyChecker',
              'outputFormat',
              'syncMode',
              'strength',
              'acceleration',
              'safetyTolerance',
              'useMultipleImages',
              // snake_case known keys
              'image_url',
              'mask_url',
